
Add-Type -TypeDefinition 'using System;using System.Runtime.InteropServices;public class DisplayHelper{[DllImport("user32.dll")]public static extern int ChangeDisplaySettings(ref DEVMODE dm,int flags);[DllImport("user32.dll")]public static extern bool EnumDisplaySettings(string name,int num,ref DEVMODE dm);[StructLayout(LayoutKind.Sequential,CharSet=CharSet.Ansi)]public struct DEVMODE{[MarshalAs(UnmanagedType.ByValTStr,SizeConst=32)]public string dmDeviceName;public short dmSpecVersion,dmDriverVersion,dmSize,dmDriverExtra;public int dmFields;public int dmPositionX,dmPositionY,dmDisplayOrientation,dmDisplayFixedOutput;public short dmColor,dmDuplex,dmYResolution,dmTTOption,dmCollate;[MarshalAs(UnmanagedType.ByValTStr,SizeConst=32)]public string dmFormName;public short dmLogPixels;public int dmBitsPerPel,dmPelsWidth,dmPelsHeight,dmDisplayFlags,dmDisplayFrequency;}}'; $m=New-Object DisplayHelper+DEVMODE; $m.dmSize=[System.Runtime.InteropServices.Marshal]::SizeOf($m); [DisplayHelper]::EnumDisplaySettings($null,-1,[ref]$m)|Out-Null; $m.dmDisplayFrequency=60; $m.dmFields=0x400000; [DisplayHelper]::ChangeDisplaySettings([ref]$m,0)
